INSERT INTO rooms (id, numeral, title, date_range, wall_text, sort) VALUES (1, 'I', 'The Republic', '1841 – 1851', 'Texas began as an act of paperwork: boundaries drawn in London and Philadelphia, a navy financed with warrants, a republic that existed most convincingly in print. The maps in this room kept the Republic alive for years after annexation made it a state.', 1) ON CONFLICT (numeral) DO NOTHING;
INSERT INTO rooms (id, numeral, title, date_range, wall_text, sort) VALUES (2, 'II', 'Secession', '1861 – 1862', 'Sam Houston won Texas its independence and spent his last office warning the state against throwing it away. Texas seceded anyway, and for four years its treasury fought the war the only way it could, with paper promises against a Union blockade.', 2) ON CONFLICT (numeral) DO NOTHING;
INSERT INTO rooms (id, numeral, title, date_range, wall_text, sort) VALUES (3, 'III', 'The Engineered Coast', '1865 – 1896', 'After the war, Texas rebuilt itself by census and by dredge. Galveston was the front door: the busiest cotton port on the Gulf, and after the jetties reached deep water in 1896, an engineered harbor built to rival New Orleans. The engineering record of this coast is the reason this collection exists.', 3) ON CONFLICT (numeral) DO NOTHING;
INSERT INTO rooms (id, numeral, title, date_range, wall_text, sort) VALUES (4, 'IV', 'The Storm', 'September 8, 1900', 'On September 8, 1900, a hurricane put the Gulf of Mexico over Galveston Island. At least 6,000 people died, the deadliest natural disaster in American history. Within days, stereoview photographers were working in the ruins, and the nation viewed the catastrophe in three dimensions.', 4) ON CONFLICT (numeral) DO NOTHING;
INSERT INTO rooms (id, numeral, title, date_range, wall_text, sort) VALUES (5, 'V', 'The Seawall', '1902 – 1915', 'Galveston answered the storm with the largest municipal engineering project of its era: a concrete seawall seventeen feet high, and behind it a city raised on jackscrews while dredged sand was pumped beneath. When a comparable hurricane struck in 1915, the wall held.', 5) ON CONFLICT (numeral) DO NOTHING;
INSERT INTO rooms (id, numeral, title, date_range, wall_text, sort) VALUES (6, 'VI', 'Boom', '1901 – 1930', 'An hour down the coast, on January 10, 1901, the Lucas gusher blew in at Spindletop and ran wild for nine days. The oil age arrived before Galveston had finished burying its dead, and it remade Texas: new companies by the hundreds, new rail, new roads, and by 1930 a state measured in gallons and miles.', 6) ON CONFLICT (numeral) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (1, 'GCC.1841.01', 'Republic of Texas Naval Appropriation Warrant, $25', 'Republic of Texas Treasury, Austin', 'April 23, 1841', 1841, NULL, NULL, 'currency', 'April 23, 1841 · Republic of Texas Treasury, Austin · Cr. AW3, Medlar 43 · PCGS Very Fine 25', 1, 1, 'The Texas Navy was the Republic''s most expensive habit and one of its most effective instruments: a handful of ships that kept the Gulf open, harassed Mexican supply lines, and gave the young nation leverage it could not afford to buy any other way. Congress appropriated funds it did not have, and the Treasury issued warrants against future revenue. Most were redeemed, cancelled, and destroyed after annexation, which is why surviving examples are scarce. This warrant is cataloged as Criswell AW3 and Medlar 43, graded Very Fine 25 by PCGS, with a crosscut cancellation showing it completed the journey the paper promised.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (2, 'GCC.1848.01', 'Mexico, with the Republic of Texas', 'Jeremiah Greenleaf', '1848', 1848, 'Hand-colored engraving', NULL, 'map', '1848 · Jeremiah Greenleaf · Hand-colored engraving', 1, 2, 'Jeremiah Greenleaf, a Vermont geographer, first issued his universal atlas in 1842, when the Republic of Texas was six years old and its boundaries were a matter of active dispute. Later printings carried the same plates forward with modest revisions, which is how an 1848 buyer, in the closing months of the Mexican-American War, could still purchase a map of a republic that had joined the Union in 1845. Collectors prize these plates precisely for that lag: they preserve the moment when Texas was a country, hand-colored and bounded, after the moment had passed.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (3, 'GCC.1851.01', 'Texas', 'John Tallis & Co., London', '1851', 1851, 'Steel engraving by John Rapkin, with vignettes', NULL, 'map', '1851 · John Tallis & Co., London · Steel engraving by John Rapkin, with vignettes', 1, 3, 'John Tallis and Company published its Illustrated Atlas of the World between 1849 and 1853, with maps drawn and engraved by John Rapkin. The firm''s timing gives its Texas plate lasting interest: it records the state in the years around the Compromise of 1850, when Texas surrendered its claim to a panhandle reaching deep into the Rockies in exchange for federal assumption of its republic-era debt. The decorative border and vignettes were already old-fashioned when published, which is why the Tallis atlas is remembered as the end of an era rather than the start of one.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (4, 'GCC.1861.01', 'Gov. Sam Houston''s Address to the People of Texas', NULL, '1861', 1861, 'Period newspaper printing', NULL, 'document', '1861 · Period newspaper printing', 2, 1, 'Houston''s address is one of the most quoted documents of the secession winter. He argued that the North would fight, that it would fight with overwhelming resources, and that the South was gambling everything on a war it could not win. He declined to raise arms against his own state and refused equally to swear allegiance to the Confederacy, choosing removal from office over either. Four years proved his arithmetic. Period newspaper printings are how most Texans actually encountered the speech, and they survive in far smaller numbers than the reprints that came after the war made Houston a prophet.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (5, 'GCC.1862.01', 'Texas Treasury Warrant, Five Dollars', 'State of Texas', '1862', 1862, 'Military payment issue', NULL, 'currency', '1862 · State of Texas · Military payment issue', 2, 2, 'Texas issued two parallel streams of wartime paper: civil warrants for the ordinary business of government and military warrants for the war itself. Both circulated as money because there was little else to circulate, and both depreciated as Confederate fortunes fell. A soldier paid in warrants often sold them at a discount to merchants, who held them against the hope of eventual redemption. The paper trail of that system, ornate engraving over collapsing credit, is among the most direct financial records of the Confederate war in Texas.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (6, 'GCC.1862.02', 'Texas Treasury Warrant, Two Dollars Fifty', 'State of Texas, Austin', 'July 19, 1862', 1862, NULL, NULL, 'currency', 'July 19, 1862 · State of Texas, Austin · Cr. 8, Medlar 104 · PCGS Very Fine 20', 2, 3, 'The two-dollars-fifty denomination did the unglamorous work of wartime government, settling small claims and salaries in an economy stripped of coin. It is cataloged as Criswell 8 and Medlar 104. Surviving examples in collectible grade are scarcer than their face value suggests, because small warrants circulated hard and were rarely saved. The holder preserves both faces of the note, and the reverse shows the plainness of paper issued by a treasury economizing on everything, including ink.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (7, 'GCC.1865.01', 'Texas, with Plan of Galveston Harbor', 'S. Augustus Mitchell, Philadelphia', '1865', 1865, 'Hand-colored engraving', NULL, 'map', '1865 · S. Augustus Mitchell, Philadelphia · Hand-colored engraving', 3, 1, 'S. Augustus Mitchell Jr. inherited the largest map publishing operation in America and kept its Texas plate current through the 1860s and 1870s. The 1865 issue is a hinge document: it shows the county grid of a Confederate state at the moment of surrender, published for a Northern market that expected to do business there again. The Galveston inset earned its place commercially. The city was the state''s financial capital and its only serious port, and every Texas map that wanted to sell acknowledged it.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (8, 'GCC.1880.01', 'Colored Population of Texas, 1880', 'United States Census cartography', '1880', 1880, 'Lithograph', NULL, 'map', '1880 · United States Census cartography · Lithograph', 3, 2, 'The statistical atlases built from the 1870 and 1880 censuses were the first to map the American population thematically at scale, and race was among the first variables mapped. In Texas the pattern the shading reveals is the geography of slavery persisting a generation after emancipation: freedpeople concentrated where cotton had concentrated, along the Brazos and Colorado bottoms and in the counties toward Louisiana. Sheets like this one framed the era''s political arguments over representation, labor, and land. As an object, it is data visualization seventy years before the term existed.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (9, 'GCC.1889.01', 'Galveston Harbor, Texas: Survey of May and June 1889', 'U.S. Army Corps of Engineers', '1889', 1889, NULL, NULL, 'map', '1889 · U.S. Army Corps of Engineers · From the Annual Report of the Chief of Engineers', 3, 3, 'The collection''s thesis object: not a commercial view but the engineering record itself, a Corps of Engineers survey of Galveston Harbor made in May and June 1889 under Major Oswald H. Ernst and published with the Annual Report of the Chief of Engineers. Ernst commanded the Corps'' Galveston district during the critical years when the city''s Deep Water Committee was lobbying Congress for a national commitment to the harbor. The survey was executed by assistant engineer H. C. Ripley and Lieutenant W. C. Langfitt, and its soundings recorded the shallow bar that kept ocean shipping waiting outside the port. Congress committed to the full jetty plan the following year, and by 1896 the works had carried the channel to deep water. Ripley''s name returns later in this collection: he served on the 1902 board of engineers that designed the Galveston seawall.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (10, 'GCC.1896.01', 'Scientific American: The Galveston Jetties', 'Munn & Co., New York', 'May 28, 1896', 1896, 'Journal cover', NULL, 'print', 'May 28, 1896 · Munn & Co., New York · Journal cover', 3, 4, 'The jetties were among the largest civil works in the country: parallel walls of stone reaching miles into the Gulf, designed to make the tide itself scour the channel deep. When the depth over the bar passed twenty-five feet, Galveston celebrated deep water as a national victory, and the engineering press treated it as one. Four years later the same national press would return to Galveston for the opposite reason. In this collection the cover marks the high point of confidence, the moment the coast seemed fully mastered.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (11, 'GCC.1900.01', 'Church Street and the Tremont Hotel', NULL, '1900', 1900, 'Stereoview', NULL, 'stereoview', '1900 · Stereoview', 4, 1, 'Stereo publishers titled their Galveston cards plainly, and the plainness was the point. Viewed through a stereoscope, the flooded street acquired depth, and depth made the scale of the water believable to viewers a thousand miles from the Gulf.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (12, 'GCC.1900.02', 'The Flood District', NULL, '1900', 1900, 'Stereoview', NULL, 'stereoview', '1900 · Stereoview', 4, 2, 'The stereoview was the era''s mass visual medium, sold door to door in boxed sets. Galveston sets sold in enormous numbers, and the proceeds of some were advertised as relief contributions. The cards fixed the disaster in national memory as a three-dimensional experience, which is part of why the storm remained a byword for catastrophe for a generation.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (13, 'GCC.1900.03', 'Searching for Dead Among the Ruins', 'Keystone View Co., Meadville, Pennsylvania', 'c. 1900', 1900, NULL, NULL, 'stereoview', 'c. 1900 · Keystone View Co., Meadville, Pennsylvania', 4, 3, 'Keystone View Company was one of the giants of the stereoview trade, and its Galveston series is among the most widely distributed disaster photography of the era. Cards like this one are difficult objects, made to be looked at and hard to look at. The collection holds them as records: of the storm, and of how America consumed the storm.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (14, 'GCC.1900.04', 'Scenes from the Galveston Disaster', 'Black and White, London', '1900', 1900, 'Halftone press page', NULL, 'print', '1900 · Black and White, London · Halftone press page', 4, 4, 'Galveston was international news, a disaster without precedent in a port tied directly to the Liverpool cotton trade. The halftone process was barely a decade old as a mass medium, and pages like this one mark the transition from engraved illustration to photographic news. The captions organized chaos into narrative: the wrecked churches, the relief work, the burning of debris.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (15, 'GCC.1904.01', 'The Seawall, Now Under Construction', NULL, '1904', 1904, 'Print article', NULL, 'print', '1904 · Print article', 5, 1, 'The seawall was designed by a three-man board of engineers appointed in 1901: Brigadier General Henry M. Robert, the author of Robert''s Rules of Order; Alfred Noble; and H. C. Ripley, the same engineer whose name appears on the 1889 harbor survey in Room III. Their design was a curved concrete face on a pile foundation, fronted with granite riprap, seventeen feet above mean low tide. Behind it came the grade raising, an even larger undertaking: more than two thousand structures were lifted on jackscrews while dredges pumped sand beneath them, raising the city itself. Together the wall and the raising are still cited among the great municipal engineering feats in American history.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (16, 'GCC.1915.01', 'After the 1915 Storm', NULL, '1915', 1915, 'Real photo postcard', NULL, 'photograph', '1915 · Real photo postcard', 5, 2, 'Real photo postcards were the citizen journalism of their day, printed directly from negatives onto postcard stock, often by local photographers within days of an event. The 1915 storm drove a comparable surge against a city that now stood higher and behind a wall, and the difference in outcomes, thousands dead in 1900 against a toll in the city counted in the dozens in 1915, became the standard proof of the engineering. Cards like this one circulated that proof by mail.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (17, 'GCC.1901.01', 'Spindletop Oil Field', 'Keystone View Co., Beaumont', 'c. 1901–1903', 1901, NULL, NULL, 'stereoview', 'c. 1901–1903 · Keystone View Co., Beaumont', 6, 1, 'The forest of derricks records the anarchy of the early field, where leases were subdivided down to fractions of an acre and every fraction drilled. Overproduction crashed the price of oil to pennies a barrel within two years, and the hill''s first boom burned out almost as fast as it rose. The stereoview preserves the moment before that arithmetic arrived.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (18, 'GCC.1901.02', 'Spindletop Oil Field', NULL, 'c. 1901–1903', 1901, 'Stereoview', NULL, 'stereoview', 'c. 1901–1903 · Stereoview', 6, 2, 'The second great subject of Spindletop photography was the crowd: speculators, drillers, lease traders, and the merely curious, arriving on every train. Stereo cards like this one sold the boom to the nation as the storm cards had sold the disaster, and together they fixed the Texas coast in the American imagination as a place where fortune and catastrophe arrived at the same scale.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (19, 'GCC.1902.01', 'Star Petroleum Company Stock Certificate', NULL, '1902', 1902, NULL, NULL, 'certificate', '1902 · Spindletop-era charter', 6, 3, 'Spindletop''s first legacy was corporate rather than geological. The Texas Company and Gulf Oil both trace to the hill, and so do hundreds of ventures that never returned a dollar, sold to investors on the strength of a map and an adjective. Certificates like this one were often the only thing a company ever produced, which gives them a documentary value their issuers never intended: a census of the boom''s ambition, one engraved share at a time.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (20, 'GCC.1910.01', 'Texas Oil Stock, Signed by Samuel Bronson Cooper', NULL, 'c. 1909–1913', 1910, 'Signed certificate', NULL, 'certificate', 'c. 1909–1913 · Signed certificate', 6, 4, 'Samuel Bronson Cooper represented the Beaumont district in Congress when the Lucas gusher came in; after leaving Congress in 1909 he was appointed by President Taft to the federal Board of General Appraisers. Signatures like Cooper''s did double work on a stock certificate: they lent a venture the credibility of public office, and they recorded how thoroughly the boom absorbed the region''s political class. Cooper had spent his congressional career on the tariff and river-and-harbor questions that mattered to Southeast Texas, and the oil age simply became the next of those interests. The certificate survives as a small document of that transition, from cotton politics to petroleum politics.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (21, 'GCC.1909.01', 'Railroad Spike, Buffalo Bayou, Brazos & Colorado Line', NULL, '1909', 1909, 'Iron', NULL, 'object', '1909 · Iron · Recovered near Alleyton, Texas', 6, 5, 'The Buffalo Bayou, Brazos and Colorado was chartered in 1850 as the first railroad in Texas, built to move cotton toward Galveston''s wharves, and this spike, dated 1909, was recovered from the old line near Alleyton. During the Civil War, Alleyton was where the railroad stopped and the cotton road began: bales went by wagon from the railhead toward the Rio Grande and out through Mexico past the blockade. The BBB&C was folded into the Galveston, Harrisburg and San Antonio and eventually the Southern Pacific system, and by 1909 its right of way was boom infrastructure, feeding oil and lumber where it had fed cotton. The spike is the collection''s one piece of the railroad itself, iron rather than paper.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (22, 'GCC.1905.01', 'Map of Texas and Indian Territory', NULL, '1905', 1905, 'Lithograph', '21.5 x 13.5 in.', 'map', '1905 · Lithograph · 21.5 x 13.5 in.', 6, 6, 'Commercial lithographed maps like this one were working documents, sold to shippers, land agents, and settlers who read them for railroads first and rivers second. The paired mapping of Texas with Indian Territory records the last moment of the old arrangement; Oklahoma statehood came in November 1907. For this collection the map is the before picture of the automobile age that closes the room.', TRUE) ON CONFLICT (accession) DO NOTHING;
INSERT INTO pieces (id, accession, title, maker, date_display, date_sort_year, medium, dimensions, object_type, meta, room_id, room_order, label, is_public) VALUES (23, 'GCC.1930.01', 'Texas License Plate No. 779-987', NULL, '1930', 1930, 'Painted steel', NULL, 'object', '1930 · Painted steel', 6, 7, 'The plate closes the collection''s arc deliberately. The republic in Room I was paper; the coast in Room III was engineered; the storm was survived; the oil age arrived; and its end product was ordinary motion, a stamped steel rectangle bolted to a car on a farm-to-market road. Objects like this one are the reason the collection does not end with a document: some history is iron and steel.', TRUE) ON CONFLICT (accession) DO NOTHING;
